def associa_numeri():
    risultati = []
    for p in paesi:
        versione = random.randint(0,19)
        versione = versione*5
        for i in range(5):
            risultati.append((versioni[versione + i][4], p[0]))
    return risultati

def stampa_risultati(risultati):
    n = 0
    for v, p in risultati:
        n = n+1
        print(f'({v}, "{p}"),', end="")
        if(n % 50 == 0):
            print(" ")

if __name__ == "__main__":
    risultati = associa_numeri()
    stampa_risultati(risultati)

